    content_blocks = EXCLUDED.content_blocks,
    status = EXCLUDED.status,
    language = EXCLUDED.language,
    reading_time_minutes = EXCLUDED.reading_time_minutes,
    published_at = EXCLUDED.published_at,
    seo_title = EXCLUDED.seo_title,
    seo_description = EXCLUDED.seo_description,
    updated_at = NOW();

INSERT INTO blog_posts (
  slug, title, excerpt, cover_image_url, content_markdown, content_html, content_blocks,
  status, language, reading_time_minutes, published_at, seo_title, seo_description
)
VALUES
(
  'healthcare-stroke-prediction',
  'Healthcare Stroke Prediction',
  'A patient-level stroke risk pipeline with deduplication, SHAP analysis, and synthetic energy expenditure features.',
  '/assets/blog/stroke-roc-curves.png',
  '# Healthcare Stroke Prediction\n\nThis project merges clinical data, feature synthesis, and threshold-aware classification.',
  '<h2>Healthcare Stroke Prediction</h2><p>This project merges clinical data, feature synthesis, and threshold-aware classification.</p>',
  '[
    {"id":"stroke-1","type":"heading","data":{"level":2,"text":"I. INTRODUCTION"}},
    {"id":"stroke-2","type":"paragraph","data":{"text":"Stroke prediction is a high-stakes classification problem because false negatives can delay care while false positives can overload triage workflows. The paper focuses on making the evaluation patient-level rather than row-level, which is the right way to avoid leakage in a repeated-visit dataset."}},
    {"id":"stroke-2b","type":"paragraph","data":{"text":"The broader goal is not to maximize a single score in isolation, but to build a screening pipeline that can be interpreted, tuned, and deployed responsibly. That is why the article combines classical classifiers, threshold selection, and SHAP analysis in one flow."}},
    {"id":"stroke-3","type":"heading","data":{"level":2,"text":"II. RELATED WORK"}},
    {"id":"stroke-3b","type":"paragraph","data":{"text":"Previous stroke studies often report strong metrics on row-level splits, but the numbers can collapse once patient identity is respected. This project intentionally follows a stricter protocol so that performance reflects actual generalization rather than memorization of repeated encounters."}},
    {"id":"stroke-4","type":"heading","data":{"level":2,"text":"III. MATERIALS AND METHODS"}},
    {"id":"stroke-4a","type":"heading","data":{"level":3,"text":"A. Dataset Description"}},
    {"id":"stroke-4b","type":"paragraph","data":{"text":"The raw table contains 143,960 visit rows that are collapsed into 5,110 unique patient profiles. Key clinical variables include age, blood pressure, cholesterol, glucose, body size, and self-reported lifestyle indicators."}},
    {"id":"stroke-4c","type":"heading","data":{"level":3,"text":"B. Patient-Level Deduplication"}},
    {"id":"stroke-4d","type":"paragraph","data":{"text":"Deduplication is performed before any split so that a patient never appears in both training and testing partitions. This step removes leakage from repeated rows and makes the evaluation meaningful."}},
    {"id":"stroke-4e","type":"heading","data":{"level":3,"text":"C. Stratified Patient-Level Split"}},
    {"id":"stroke-4f","type":"paragraph","data":{"text":"The split is stratified to preserve the class balance across train, validation, and test sets. Threshold tuning is done on validation data only, then locked before final reporting."}},
    {"id":"stroke-4g","type":"heading","data":{"level":3,"text":"D. Synthetic Energy Expenditure Estimation"}},
    {"id":"stroke-4h","type":"paragraph","data":{"text":"A separate exercise regression task estimates calories burned and converts that output into a behavioral proxy. The synthetic feature is used to enrich the feature space without pretending to replace a measured clinical signal."}},
    {"id":"stroke-4i","type":"heading","data":{"level":3,"text":"E. Feature Selection and Anomaly Analysis"}},
    {"id":"stroke-4j","type":"paragraph","data":{"text":"Feature importance and correlation checks are used to identify noisy or suspicious variables. The analysis also highlights where some engineered measurements behave differently from the rest of the cohort."}},
    {"id":"stroke-4k","type":"heading","data":{"level":3,"text":"F. Classification Models"}},
    {"id":"stroke-4l","type":"paragraph","data":{"text":"Several classical models are compared, including Logistic Regression, Random Forest, Extra Trees, Gradient Boosting, Histogram Gradient Boosting, and XGBoost. This keeps the experiment reproducible and easy to benchmark."}},
    {"id":"stroke-4m","type":"heading","data":{"level":3,"text":"G. Decision Threshold Optimization"}},
    {"id":"stroke-4n","type":"paragraph","data":{"text":"Because the dataset is imbalanced, threshold choice matters as much as classifier choice. Validation-set threshold tuning is used to balance recall, precision, and the downstream screening objective."}},
    {"id":"stroke-5","type":"heading","data":{"level":2,"text":"IV. EXPERIMENTAL RESULTS"}},
    {"id":"stroke-5a","type":"heading","data":{"level":3,"text":"A. Experimental Setup"}},
    {"id":"stroke-5b","type":"paragraph","data":{"text":"The evaluation protocol reports accuracy, precision, recall, F1, and AUC under a fixed held-out patient test set. The reported numbers are intentionally paired with threshold values so the operating point is explicit."}},
    {"id":"stroke-5c","type":"heading","data":{"level":3,"text":"B. Calorie Regressor Performance"}},
    {"id":"stroke-5d","type":"paragraph","data":{"text":"The separate calorie regressor provides the synthetic energy feature used in the stroke model. Its role is auxiliary, but it helps demonstrate how a behavioral signal can be attached to a clinical classifier."}},
    {"id":"stroke-5e","type":"heading","data":{"level":3,"text":"C. Stroke Classifier Comparison"}},
    {"id":"stroke-5f","type":"paragraph","data":{"text":"Gradient Boosting gives the strongest F1 at its chosen threshold, while XGBoost gives the strongest ranking quality and recall. That is why the final paper distinguishes between screening-oriented and balanced operating points."}},
    {"id":"stroke-img-1","type":"image","data":{"url":"/assets/blog/stroke-confusion-matrix.png","alt":"Stroke confusion matrix","caption":"Confusion matrix on the held-out patient test set."}},
    {"id":"stroke-img-2","type":"image","data":{"url":"/assets/blog/stroke-roc-curves.png","alt":"ROC curves for stroke models","caption":"ROC curves for six classifiers, with XGBoost selected as the best performer."}},
    {"id":"stroke-5g","type":"heading","data":{"level":3,"text":"D. ROC Curve Analysis"}},
    {"id":"stroke-5h","type":"paragraph","data":{"text":"The ROC curves show that the class imbalance does not prevent useful separation when thresholding is handled carefully. XGBoost is selected because it balances recall and ranking performance better than the other candidates."}},
    {"id":"stroke-5i","type":"heading","data":{"level":3,"text":"E. SHAP Feature Importance"}},
    {"id":"stroke-5j","type":"paragraph","data":{"text":"SHAP ranks age and average glucose among the strongest contributors, which is consistent with common stroke risk intuition. This section is important because it translates a black-box score into a human-readable explanation."}},
    {"id":"stroke-5k","type":"heading","data":{"level":3,"text":"G. Anomalous Feature Diagnostics"}},
    {"id":"stroke-5l","type":"paragraph","data":{"text":"Pearson correlation and ablation tests expose where certain engineered variables behave oddly. Those diagnostics are useful because they prevent the project from overclaiming the value of a noisy feature."}},
    {"id":"stroke-table-1","type":"table","data":{"title":"Table I. Classifier performance on the deduplicated test set","headers":["Model","Thresh.","Acc.","Prec.","Recall","F1","AUC"],"rows":[["Grad. Boost.","0.080","83.6%","19.0%","71.1%","0.300","0.857"],["Log. Reg.","0.605","81.2%","17.7%","76.3%","0.287","0.859"],["XGBoost","0.585","79.5%","17.1%","81.6%","0.283","0.863"],["Rand. Forest","0.570","81.7%","17.3%","71.1%","0.278","0.853"],["Extra Trees","0.570","80.3%","17.0%","76.3%","0.278","0.848"],["Hist. GB","0.655","84.4%","16.9%","55.3%","0.259","0.858"]]}},
    {"id":"stroke-img-3","type":"image","data":{"url":"/assets/blog/stroke-shap-bar.png","alt":"SHAP summary bar chart","caption":"SHAP feature importance summary."}},
    {"id":"stroke-img-4","type":"image","data":{"url":"/assets/blog/stroke-shap-beeswarm.png","alt":"SHAP beeswarm plot","caption":"SHAP directionality check on the final feature set."}},
    {"id":"stroke-table-2","type":"table","data":{"title":"Table II. Anomalous feature Pearson correlations with stroke_target","headers":["Feature","r (Pearson)","Mean (No stroke)","Mean (Stroke)"],"rows":[["avg_ap_hi","-0.030","126.35","124.59"],["avg_ap_lo","-0.030","97.29","86.46"],["heart_cholesterol","-0.045","218.79","207.12"],["bmi (raw)","-0.052","27.87","25.58"]]}},
    {"id":"stroke-table-3","type":"table","data":{"title":"Table III. Feature ablation study","headers":["Feature Variant","Accuracy","F1","AUC-ROC"],"rows":[["All features","93.4%","0.243","0.740"],["Drop avg_weight, avg_height","93.4%","0.243","0.740"],["Drop bmi, keep wt/ht","91.4%","0.212","0.695"],["Drop body size, keep bmi","93.7%","0.133","0.732"]]}},
    {"id":"stroke-7","type":"code","data":{"language":"bash","code":"python Code/Model.py\\npython Code/compare_models.py\\npython Code/evaluate_model.py\\npython Code/generate_figures.py"}},
    {"id":"stroke-8","type":"heading","data":{"level":2,"text":"V. DISCUSSION"}},
    {"id":"stroke-8c","type":"paragraph","data":{"text":"The discussion frames the result as a threshold and evaluation problem more than a model-selection problem. The paper is deliberately conservative: it prefers a reproducible patient-level protocol over an overly optimistic row-level benchmark."}},
    {"id":"stroke-8d","type":"paragraph","data":{"text":"That is also why the feature diagnostics matter. They show where the data is stable, where it is noisy, and which signals should be treated as supporting evidence instead of primary evidence."}},
    {"id":"stroke-9","type":"heading","data":{"level":2,"text":"VI. C++ DEPLOYMENT PIPELINE"}},
    {"id":"stroke-9b","type":"paragraph","data":{"text":"The deployment path packages the feature engineering steps and model inference into a reproducible pipeline. That makes the work useful beyond a notebook, especially for edge or low-dependency environments."}},
    {"id":"stroke-10","type":"heading","data":{"level":2,"text":"VII. CONCLUSION"}},
    {"id":"stroke-10b","type":"quote","data":{"text":"XGBoost achieved the highest AUC-ROC of 0.8630 and recall of 81.58% on the held-out patient test set.","cite":"Final paper"}}
  ]'::jsonb,
  'published',
  'en',
  8,
  NOW(),
  'Healthcare Stroke Prediction',
  'A technical case study on stroke risk prediction with deduplication and SHAP.'
)
