INSERT INTO blog_posts (
  slug, title, excerpt, cover_image_url, content_markdown, content_html, content_blocks,
  status, language, reading_time_minutes, published_at, seo_title, seo_description
)
VALUES
(
  'lung-cancer-aff-cpp-inference',
  'Lung Cancer AFF + C++ Inference',
  'A hybrid CT classification system that fuses deep features, handcrafted texture descriptors, and ONNX Runtime C++ deployment.',
  '/assets/blog/lung-fig-architecture.png',
  '# Lung Cancer AFF + C++ Inference\n\nThis project blends explainable image features with edge deployment.',
  '<h2>Lung Cancer AFF + C++ Inference</h2><p>This project blends explainable image features with edge deployment.</p>',
  '[
    {"id":"lung-1","type":"heading","data":{"level":2,"text":"I. INTRODUCTION"}},
    {"id":"lung-2","type":"paragraph","data":{"text":"Lung cancer classification from CT images benefits from both deep visual features and handcrafted texture descriptors. The paper argues that a hybrid pipeline is stronger than a pure CNN when the goal is not only accuracy, but also interpretability and edge deployment."}},
    {"id":"lung-2b","type":"paragraph","data":{"text":"The work is built around a practical constraint: the final system should be explainable to a clinician and exportable to a C++ runtime. That is why the article tracks both model performance and deployment fidelity."}},
    {"id":"lung-3","type":"heading","data":{"level":2,"text":"II. RELATED WORK"}},
    {"id":"lung-3b","type":"paragraph","data":{"text":"Prior CNN-based approaches reach high accuracy on CT datasets, but they usually do not explain which visual patterns matter and they often stop at Python inference. This paper combines deep transfer learning, handcrafted texture statistics, and an explicit edge runtime to close that gap."}},
    {"id":"lung-4","type":"heading","data":{"level":2,"text":"III. PROPOSED METHODOLOGY"}},
    {"id":"lung-4a","type":"heading","data":{"level":3,"text":"A. Image Preprocessing"}},
    {"id":"lung-4b","type":"paragraph","data":{"text":"Each CT image is converted to grayscale, resized, denoised, and normalized before feature extraction. The adaptive denoising step is designed to preserve contour detail while suppressing background noise."}},
    {"id":"lung-4c","type":"heading","data":{"level":3,"text":"B. Handcrafted Texture Feature Extraction"}},
    {"id":"lung-4d","type":"paragraph","data":{"text":"GLCM and LBP capture complementary local structure cues. These descriptors make the model more robust to texture differences that a deep backbone may not always emphasize on its own."}},
    {"id":"lung-4e","type":"heading","data":{"level":3,"text":"C. Deep Feature Extraction with MSCA"}},
    {"id":"lung-4f","type":"paragraph","data":{"text":"An InceptionV3 branch extracts semantic features from resized RGB input. The paper uses the mixed7 layer as a compact deep representation before fusion."}},
    {"id":"lung-4g","type":"heading","data":{"level":3,"text":"D. Attentional Feature Fusion (AFF)"}},
    {"id":"lung-4h","type":"paragraph","data":{"text":"AFF learns how much to trust the deep branch and the handcrafted branch for each sample. The point is not to concatenate everything blindly, but to make the fusion adaptive and data-dependent."}},
    {"id":"lung-4i","type":"heading","data":{"level":3,"text":"E. Classification and Explainability"}},
    {"id":"lung-4j","type":"paragraph","data":{"text":"The fused vector is passed into an MLP classifier, and explanation outputs are derived from the learned representation. The article pairs performance tables with class-level metrics so the reader can inspect the model beyond a single aggregate score."}},
    {"id":"lung-4k","type":"heading","data":{"level":3,"text":"F. Edge Deployment via C++ ONNX Runtime"}},
    {"id":"lung-4l","type":"paragraph","data":{"text":"The full preprocessing and inference pipeline is exported to ONNX and replayed in C++ using ONNX Runtime and OpenCV. This step validates that the research model can survive outside the Python notebook without changing the prediction behavior."}},
    {"id":"lung-img-1","type":"image","data":{"url":"/assets/blog/lung-fig-architecture.png","alt":"Hybrid architecture","caption":"Overall architecture of the hybrid explainable lung cancer framework."}},
    {"id":"lung-img-2","type":"image","data":{"url":"/assets/blog/lung-test-ct.png","alt":"Test CT input","caption":"Example CT input used by the C++ inference demo."}},
    {"id":"lung-img-3","type":"image","data":{"url":"/assets/blog/lung-confusion-matrix.png","alt":"Lung cancer confusion matrix","caption":"Cross-validation confusion matrix from the paper."}},
    {"id":"lung-img-4","type":"image","data":{"url":"/assets/blog/lung-roc-curves.png","alt":"Lung cancer ROC curves","caption":"ROC curves for the three-class classifier."}},
    {"id":"lung-img-5","type":"image","data":{"url":"/assets/blog/lung-ext-prediction.png","alt":"External prediction distribution","caption":"External dataset prediction distribution for robustness checks."}},
    {"id":"lung-5","type":"heading","data":{"level":2,"text":"IV. EXPERIMENTAL RESULTS"}},
    {"id":"lung-5a","type":"heading","data":{"level":3,"text":"A. Dataset and Experimental Setup"}},
    {"id":"lung-5b","type":"paragraph","data":{"text":"The IQ-OTHNCCD dataset contains 1,097 CT images across benign, malignant, and normal classes. The evaluation reports cross-validation metrics, class balance, and deployment validation so the experimental section reads like a paper rather than a demo log."}},
    {"id":"lung-5c","type":"heading","data":{"level":3,"text":"B. Classification Performance"}},
    {"id":"lung-5d","type":"paragraph","data":{"text":"The proposed hybrid system achieves strong weighted precision, recall, and F1 across folds. The result is important because it shows that the fused representation is stable and not overly dependent on a single class."}},
    {"id":"lung-5e","type":"heading","data":{"level":3,"text":"C. Comparison with Existing Methods"}},
    {"id":"lung-5f","type":"paragraph","data":{"text":"The paper positions the hybrid AFF approach against prior CT classification methods and argues that the fusion design improves both performance and interpretability. This is the main evidence that the added handcrafted branch is worth keeping."}},
    {"id":"lung-5g","type":"heading","data":{"level":3,"text":"D. Preprocessing Analysis"}},
    {"id":"lung-5h","type":"paragraph","data":{"text":"The denoising example shows that the preprocessing step reduces noise without erasing lesion boundaries. That matters because the handcrafted descriptors are sensitive to local texture and edge structure."}},
    {"id":"lung-5i","type":"heading","data":{"level":3,"text":"E. External Generalizability Evaluation"}},
    {"id":"lung-5j","type":"paragraph","data":{"text":"An external dataset is used to check whether the model generalizes beyond the source distribution. This section is the paper's answer to the usual criticism that medical models only work on one dataset."}},
    {"id":"lung-5k","type":"heading","data":{"level":3,"text":"F. Edge Deployment Validation"}},
    {"id":"lung-5l","type":"paragraph","data":{"text":"The C++ runtime is validated against the Python implementation to confirm feature parity and consistent outputs. The deployment story is as important as the classifier accuracy because the goal is practical portability."}},
    {"id":"lung-table-1","type":"table","data":{"title":"Table I. IQ-OTHNCCD dataset statistics","headers":["Class","Number of Images","Percentage"],"rows":[["Benign","120","10.94%"],["Malignant","561","51.14%"],["Normal","416","37.92%"],["Total","1,097","100.00%"]]}},
    {"id":"lung-table-2","type":"table","data":{"title":"Table II. Per-class validation metrics (5-fold CV)","headers":["Class","Precision","Recall","F1-Score","Support"],"rows":[["Benign","0.9735","0.9167","0.9442","120"],["Malignant","0.9947","0.9947","0.9947","561"],["Normal","0.9716","0.9880","0.9797","416"],["Weighted Avg","0.9841","0.9836","0.9835","1,097"]]}},
    {"id":"lung-table-3","type":"table","data":{"title":"Table III. Comparison with existing methods","headers":["Method","Dataset","Accuracy (%)","AUC"],"rows":[["VGG16 + SVM [17]","IQ-OTHNCCD","94.50","0.9520"],["ResNet50 [18]","IQ-OTHNCCD","96.20","0.9710"],["DenseNet121 [18]","IQ-OTHNCCD","95.80","0.9680"],["EfficientNet-B0 [19]","IQ-OTHNCCD","97.30","0.9850"],["InceptionV3 + GLCM [9]","IQ-OTHNCCD","98.10","0.9910"],["Proposed (AFF + MSCA)","IQ-OTHNCCD","98.36","0.9967"]]}},
    {"id":"lung-table-4","type":"table","data":{"title":"Table IV. C++ edge deployment characteristics","headers":["Metric","Value"],"rows":[["ONNX Model Size","45.3 MB"],["Runtime","ONNX Runtime 1.26.0"],["Compiler","MSVC 19.51 (C++17)"],["Feature Precision Match","< 10^-5 (all 58 features)"],["Prediction Agreement","100% identical to Python"]]}},
    {"id":"lung-8","type":"code","data":{"language":"cpp","code":"string imagePath = \\\"test_ct.png\\\";\\nmean = loadNpyVector(\\\"glcm_lbp_mean.npy\\\");\\nstd_dev = loadNpyVector(\\\"glcm_lbp_std.npy\\\");\\ncout << \\\"Da load thanh cong model.onnx!\\\" << endl;"}},
    {"id":"lung-9","type":"heading","data":{"level":2,"text":"V. CONCLUSION"}},
    {"id":"lung-9b","type":"paragraph","data":{"text":"The final validation story is about consistency: model predictions, heatmaps, and C++ inference output are aligned so the system can be reasoned about as one pipeline rather than a collection of disconnected scripts."}},
    {"id":"lung-10","type":"quote","data":{"text":"The entire pipeline is exported to ONNX format and deployed through a high-performance C++ inference engine using ONNX Runtime and OpenCV.","cite":"Final paper"}}
  ]'::jsonb,
  'published',
  'en',
  9,
  NOW(),
  'Lung Cancer AFF + C++ Inference',
  'Explainable lung cancer classification with feature fusion and edge deployment.'
)
